+/**
+ * Notification preferences service — per-user channel overrides.
+ *
+ * Allows users to specify a preferred notification channel that overrides
+ * the default priority-based routing. For example, a user might always
+ * want SMS regardless of notification priority.
+ */
+
+export type ChannelPreference = 'sms' | 'email' | 'webhook';
+
+export interface UserPreference {
+  userId: string;
+  preferredChannel: ChannelPreference;
+}
+
+export class NotificationPreferencesService {
+  private preferences = new Map<string, ChannelPreference>();
+
+  /**
+   * Set a user's preferred notification channel.
+   */
+  setPreference(userId: string, channel: ChannelPreference): void {
+    this.preferences.set(userId, channel);
+  }
+
+  /**
+   * Get a user's preferred channel, or null if no preference is set.
+   */
+  getPreference(userId: string): ChannelPreference | null {
+    return this.preferences.get(userId) ?? null;
+  }
+
+  /**
+   * Remove a user's channel preference (reverts to priority-based routing).
+   */
+  removePreference(userId: string): boolean {
+    return this.preferences.delete(userId);
+  }
+
+  /**
+   * Check whether a user has a channel preference set.
+   */
+  hasPreference(userId: string): boolean {
+    return this.preferences.has(userId);
+  }
+
+  /**
+   * Get all stored preferences.
+   */
+  getAllPreferences(): UserPreference[] {
+    return Array.from(this.preferences.entries()).map(([userId, preferredChannel]) => ({
+      userId,
+      preferredChannel,
+    }));
+  }
+
+  clear(): void {
+    this.preferences.clear();
+  }
+}

