/**
 * Audit logging service — records every notification dispatched.
 *
 * Provides a tamper-evident log of all notifications routed through the
 * system, capturing channel, priority, recipient, and timing metadata.
 */

import type { NotificationPriority, RouteResult } from './priority-router.js';

export interface AuditEntry {
  id: string;
  timestamp: Date;
  channel: 'sms' | 'email' | 'webhook';
  priority: NotificationPriority;
  recipient: string;
  subject: string;
  success: boolean;
  overriddenByPreference: boolean;
}

let nextId = 1;

function generateAuditId(): string {
  return `audit-${String(nextId++).padStart(4, '0')}`;
}

export function resetAuditIdCounter(): void {
  nextId = 1;
}

export class AuditService {
  private entries: AuditEntry[] = [];

  /**
   * Record a dispatched notification.
   */
  record(params: {
    channel: 'sms' | 'email' | 'webhook';
    priority: NotificationPriority;
    recipient: string;
    subject: string;
    success: boolean;
    overriddenByPreference?: boolean;
  }): AuditEntry {
    const entry: AuditEntry = {
      id: generateAuditId(),
      timestamp: new Date(),
      channel: params.channel,
      priority: params.priority,
      recipient: params.recipient,
      subject: params.subject,
      success: params.success,
      overriddenByPreference: params.overriddenByPreference ?? false,
    };
    this.entries.push(entry);
    return entry;
  }

  getEntries(): AuditEntry[] {
    return [...this.entries];
  }

  getEntriesForRecipient(recipient: string): AuditEntry[] {
    return this.entries.filter((e) => e.recipient === recipient);
  }

  getEntriesByChannel(channel: 'sms' | 'email' | 'webhook'): AuditEntry[] {
    return this.entries.filter((e) => e.channel === channel);
  }

  getEntryCount(): number {
    return this.entries.length;
  }

  clear(): void {
    this.entries = [];
  }
}

/**
 * Notification preferences service — per-user channel overrides.
 *
 * Allows users to specify a preferred notification channel that overrides
 * the default priority-based routing. For example, a user might always
 * want SMS regardless of notification priority.
 */

export type ChannelPreference = 'sms' | 'email' | 'webhook';

export interface UserPreference {
  userId: string;
  preferredChannel: ChannelPreference;
}

export class NotificationPreferencesService {
  private preferences = new Map<string, ChannelPreference>();

  /**
   * Set a user's preferred notification channel.
   */
  setPreference(userId: string, channel: ChannelPreference): void {
    this.preferences.set(userId, channel);
  }

  /**
   * Get a user's preferred channel, or null if no preference is set.
   */
  getPreference(userId: string): ChannelPreference | null {
    return this.preferences.get(userId) ?? null;
  }

  /**
   * Remove a user's channel preference (reverts to priority-based routing).
   */
  removePreference(userId: string): boolean {
    return this.preferences.delete(userId);
  }

  /**
   * Check whether a user has a channel preference set.
   */
  hasPreference(userId: string): boolean {
    return this.preferences.has(userId);
  }

  /**
   * Get all stored preferences.
   */
  getAllPreferences(): UserPreference[] {
    return Array.from(this.preferences.entries()).map(([userId, preferredChannel]) => ({
      userId,
      preferredChannel,
    }));
  }

  clear(): void {
    this.preferences.clear();
  }
}

