route(notification: PriorityNotification): RouteResult {
  // Check for per-user channel preference override
  const preferredChannel = this.preferencesService?.getPreference(notification.recipient) ?? null;
  const overridden = preferredChannel !== null;
  const targetChannel = preferredChannel ?? this.channelForPriority(notification.priority);

  this.logger.info(
    `Routing ${notification.priority} notification to ${targetChannel}${overridden ? ' (user preference override)' : ''}`,
  );

  let result: RouteResult;
  switch (targetChannel) {
    case 'sms':
      result = this.routeToSms(notification);
      break;
    case 'email':
      result = this.routeToEmail(notification);
      break;
    case 'webhook':
      result = this.routeToWebhook(notification);
      break;
    default: {
      const _exhaustive: never = targetChannel;
      throw new Error(`Unknown channel: ${_exhaustive}`);
    }
  }

  // Preserve original priority in result
  result.priority = notification.priority;

  if (this.auditService) {
    this.auditService.record({
      channel: result.channel,
      priority: notification.priority,
      recipient: notification.recipient,
      subject: notification.subject,
      success: result.success,
      overriddenByPreference: overridden,
    });
  }

  return result;
}

