import { AuditService, resetAuditIdCounter } from '../../src/services/audit.service.js';

describe('AuditService', () => {
  let audit: AuditService;

  beforeEach(() => {
    audit = new AuditService();
    resetAuditIdCounter();
  });

  it('should record an audit entry', () => {
    const entry = audit.record({
      channel: 'sms',
      priority: 'urgent',
      recipient: 'user-1',
      subject: 'Alert',
      success: true,
    });

    expect(entry.id).toBe('audit-0001');
    expect(entry.channel).toBe('sms');
    expect(entry.priority).toBe('urgent');
    expect(entry.recipient).toBe('user-1');
    expect(entry.subject).toBe('Alert');
    expect(entry.success).toBe(true);
    expect(entry.overriddenByPreference).toBe(false);
    expect(entry.timestamp).toBeInstanceOf(Date);
  });

  it('should record overriddenByPreference flag', () => {
    const entry = audit.record({
      channel: 'email',
      priority: 'urgent',
      recipient: 'user-1',
      subject: 'Alert',
      success: true,
      overriddenByPreference: true,
    });

    expect(entry.overriddenByPreference).toBe(true);
  });

  it('should return all entries', () => {
    audit.record({ channel: 'sms', priority: 'urgent', recipient: 'a', subject: 's1', success: true });
    audit.record({ channel: 'email', priority: 'normal', recipient: 'b', subject: 's2', success: true });

    expect(audit.getEntries()).toHaveLength(2);
    expect(audit.getEntryCount()).toBe(2);
  });

  it('should filter entries by recipient', () => {
    audit.record({ channel: 'sms', priority: 'urgent', recipient: 'alice', subject: 's1', success: true });
    audit.record({ channel: 'email', priority: 'normal', recipient: 'bob', subject: 's2', success: true });
    audit.record({ channel: 'webhook', priority: 'low', recipient: 'alice', subject: 's3', success: true });

    expect(audit.getEntriesForRecipient('alice')).toHaveLength(2);
    expect(audit.getEntriesForRecipient('bob')).toHaveLength(1);
  });

  it('should filter entries by channel', () => {
    audit.record({ channel: 'sms', priority: 'urgent', recipient: 'a', subject: 's1', success: true });
    audit.record({ channel: 'sms', priority: 'urgent', recipient: 'b', subject: 's2', success: true });
    audit.record({ channel: 'email', priority: 'normal', recipient: 'c', subject: 's3', success: true });

    expect(audit.getEntriesByChannel('sms')).toHaveLength(2);
    expect(audit.getEntriesByChannel('email')).toHaveLength(1);
    expect(audit.getEntriesByChannel('webhook')).toHaveLength(0);
  });

  it('should clear all entries', () => {
    audit.record({ channel: 'sms', priority: 'urgent', recipient: 'a', subject: 's', success: true });
    audit.clear();

    expect(audit.getEntryCount()).toBe(0);
  });

  it('should generate sequential IDs', () => {
    const e1 = audit.record({ channel: 'sms', priority: 'urgent', recipient: 'a', subject: 's', success: true });
    const e2 = audit.record({ channel: 'email', priority: 'normal', recipient: 'b', subject: 's', success: true });

    expect(e1.id).toBe('audit-0001');
    expect(e2.id).toBe('audit-0002');
  });
});

