import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import {
  SmsChannelService,
  resetSmsIdCounter,
} from '../../src/services/sms-channel.service.js';
import {
  WebhookChannelService,
  resetWebhookDeliveryIdCounter,
} from '../../src/services/webhook-channel.service.js';
import { PriorityRouter } from '../../src/services/priority-router.js';
import { AuditService, resetAuditIdCounter } from '../../src/services/audit.service.js';
import { NotificationPreferencesService } from '../../src/services/notification-preferences.service.js';
import { statusChangeCallbacks } from '../../src/utils/callback-registry.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

describe('Notification flow integration', () => {
  let eventBus: EventBus;
  let emailChannel: NotificationService;
  let smsChannel: SmsChannelService;
  let webhookChannel: WebhookChannelService;
  let router: PriorityRouter;
  let audit: AuditService;
  let prefs: NotificationPreferencesService;

  beforeEach(() => {
    eventBus = new EventBus();
    statusChangeCallbacks.clear();
    emailChannel = new NotificationService(eventBus);
    smsChannel = new SmsChannelService(eventBus);
    webhookChannel = new WebhookChannelService(eventBus);
    audit = new AuditService();
    prefs = new NotificationPreferencesService();
    router = new PriorityRouter(emailChannel, smsChannel, webhookChannel);
    router.setAuditService(audit);
    router.setPreferencesService(prefs);
    emailChannel.setPriorityRouter(router);
    resetNotificationIdCounter();
    resetSmsIdCounter();
    resetWebhookDeliveryIdCounter();
    resetAuditIdCounter();
  });

  // --- Priority routing → channel selection → audit ---

  describe('priority routing with audit logging', () => {
    it('urgent order → SMS channel + audit entry', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Laptop', quantity: 1, unitPrice: 200 }],
          total: 200,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // SMS received the urgent notification
      const smsMessages = smsChannel.getMessages();
      const routedMsg = smsMessages.find((m) => m.body.includes('[URGENT]'));
      expect(routedMsg).toBeDefined();

      // Audit recorded the dispatch
      const entries = audit.getEntries();
      const auditEntry = entries.find((e) => e.channel === 'sms' && e.priority === 'urgent');
      expect(auditEntry).toBeDefined();
      expect(auditEntry!.recipient).toBe('alice@example.com');
      expect(auditEntry!.success).toBe(true);
      expect(auditEntry!.overriddenByPreference).toBe(false);
    });

    it('normal order → email channel + audit entry', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-2',
          userId: 'user-2',
          items: [{ productId: 'p2', name: 'Book', quantity: 1, unitPrice: 50 }],
          total: 50,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-2',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const emailNotifs = emailChannel.getNotifications();
      const routedNotif = emailNotifs.find((n) => n.subject.includes('Order Confirmation'));
      expect(routedNotif).toBeDefined();
      expect(routedNotif!.recipient).toBe('bob@example.com');

      const auditEntry = audit.getEntries().find((e) => e.channel === 'email' && e.priority === 'normal');
      expect(auditEntry).toBeDefined();
      expect(auditEntry!.recipient).toBe('bob@example.com');
      expect(auditEntry!.overriddenByPreference).toBe(false);
    });

    it('low-value order → webhook channel + audit entry', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-3',
          userId: 'user-3',
          items: [{ productId: 'p3', name: 'Sticker', quantity: 1, unitPrice: 5 }],
          total: 5,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-3',
          name: 'Carol',
          email: 'carol@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const auditEntry = audit.getEntries().find((e) => e.channel === 'webhook' && e.priority === 'low');
      expect(auditEntry).toBeDefined();
      expect(auditEntry!.recipient).toBe('carol@example.com');
    });

    it('cancellation status change → SMS (urgent) + audit entry', () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-4',
          userId: 'user-4',
          items: [],
          total: 20,
          status: 'cancelled',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'cancelled',
        timestamp: new Date(),
      };

      statusChangeCallbacks.notify(event);

      const smsMsg = smsChannel.getMessages().find((m) => m.body.includes('[URGENT]'));
      expect(smsMsg).toBeDefined();

      const auditEntry = audit.getEntries().find((e) => e.channel === 'sms' && e.priority === 'urgent');
      expect(auditEntry).toBeDefined();
      expect(auditEntry!.recipient).toBe('user-4');
    });
  });

  // --- User preference overrides ---

  describe('user preference overrides', () => {
    it('should override urgent→SMS to email when user prefers email', async () => {
      prefs.setPreference('alice@example.com', 'email');

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-5',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Laptop', quantity: 1, unitPrice: 200 }],
          total: 200,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Should go to email despite being urgent
      const emailNotifs = emailChannel.getNotifications();
      const routedNotif = emailNotifs.find((n) => n.subject.includes('Order Confirmation'));
      expect(routedNotif).toBeDefined();

      // Audit shows override
      const auditEntry = audit.getEntries().find(
        (e) => e.recipient === 'alice@example.com' && e.channel === 'email',
      );
      expect(auditEntry).toBeDefined();
      expect(auditEntry!.priority).toBe('urgent');
      expect(auditEntry!.overriddenByPreference).toBe(true);
    });

    it('should override low→webhook to SMS when user prefers sms', () => {
      prefs.setPreference('user-5', 'sms');

      const result = router.route({
        priority: 'low',
        recipient: 'user-5',
        subject: 'Low priority notice',
        body: 'This would normally go to webhook',
        phoneNumber: '+1-555-0005',
      });

      expect(result.channel).toBe('sms');
      expect(result.priority).toBe('low');

      expect(smsChannel.getMessages().find((m) => m.body.includes('[URGENT]'))).toBeDefined();
      expect(webhookChannel.getDeliveryCount()).toBe(0);

      const auditEntry = audit.getEntries()[0]!;
      expect(auditEntry.channel).toBe('sms');
      expect(auditEntry.priority).toBe('low');
      expect(auditEntry.overriddenByPreference).toBe(true);
    });

    it('should use priority routing when user has no preference', () => {
      // No preference set for this user
      const result = router.route({
        priority: 'normal',
        recipient: 'no-pref-user',
        subject: 'Normal notice',
        body: 'Should follow standard routing',
      });

      expect(result.channel).toBe('email');
      const auditEntry = audit.getEntries()[0]!;
      expect(auditEntry.overriddenByPreference).toBe(false);
    });

    it('should revert to priority routing after preference is removed', () => {
      prefs.setPreference('user-6', 'webhook');
      prefs.removePreference('user-6');

      const result = router.route({
        priority: 'urgent',
        recipient: 'user-6',
        subject: 'Alert',
        body: 'Test',
        phoneNumber: '+1-555-0006',
      });

      expect(result.channel).toBe('sms');
      expect(audit.getEntries()[0]!.overriddenByPreference).toBe(false);
    });
  });

  // --- Multiple notifications, audit completeness ---

  describe('audit completeness', () => {
    it('should have one audit entry per routed notification', () => {
      router.route({ priority: 'urgent', recipient: 'a', subject: 's1', body: 'b1', phoneNumber: '+1-555-0001' });
      router.route({ priority: 'normal', recipient: 'b', subject: 's2', body: 'b2' });
      router.route({ priority: 'low', recipient: 'c', subject: 's3', body: 'b3' });

      expect(audit.getEntryCount()).toBe(3);
      expect(audit.getEntriesByChannel('sms')).toHaveLength(1);
      expect(audit.getEntriesByChannel('email')).toHaveLength(1);
      expect(audit.getEntriesByChannel('webhook')).toHaveLength(1);
    });

    it('should track all entries for a single recipient across channels', () => {
      prefs.setPreference('user-7', 'email');

      router.route({ priority: 'urgent', recipient: 'user-7', subject: 's1', body: 'b1' });

      prefs.removePreference('user-7');

      router.route({ priority: 'urgent', recipient: 'user-7', subject: 's2', body: 'b2', phoneNumber: '+1-555-0007' });

      const entries = audit.getEntriesForRecipient('user-7');
      expect(entries).toHaveLength(2);
      expect(entries[0]!.channel).toBe('email');
      expect(entries[0]!.overriddenByPreference).toBe(true);
      expect(entries[1]!.channel).toBe('sms');
      expect(entries[1]!.overriddenByPreference).toBe(false);
    });
  });
